// Manual Setting
let sensorId = 1; // ganti ke sensor mana yang ingin kamu pakai (1, 2, dst)
let patternId = 1; // ganti ke pattern mana yang ingin kamu pakai (1, 2, dst)

// Fungsi waktu WIB
function getWIBTime(minusSeconds = 0) {
    let date = new Date(Date.now() - (minusSeconds * 1000));
    date.setHours(date.getHours() + 7);
    return date.toISOString().slice(0, 19).replace('T', ' ');
}

// Waktu
let timeValue = getWIBTime(2);
let createdAt = getWIBTime(0);
let updatedAt = getWIBTime(0);

// Insert ke sensor_histories
msg.topic = `
    INSERT INTO sensor_histories 
    (pattern_id, sensor_id, time, duration, created_at, updated_at)
    VALUES (NULL, ${sensorId}, '${timeValue}', NULL, '${createdAt}', '${updatedAt}')
`;
return msg;

let values = msg.payload;
let queries = [];
let lastValues = context.get("lastValues") || [];

// Debug raw data
node.warn("RAW: " + JSON.stringify(values));

if (!Array.isArray(values) || values.length === 0) {
    node.error("msg.payload kosong atau tidak valid");
    return;
}

// Convert DEC → HEX formatted BCD 4 digit
function toBCDHexString(v) {
    if (v === undefined || v === null) return "0000";
    return v.toString(16).toUpperCase().padStart(4, "0");
}

function decodeBCDDatetime(v1, v2, v3) {
    let h1 = toBCDHexString(v1);
    let h2 = toBCDHexString(v2);
    let h3 = toBCDHexString(v3);

    let raw = h1 + h2 + h3;
    node.warn("Decode BCD: " + raw);

    let year = 2000 + parseInt(raw.slice(0, 2), 10);
    let month = raw.slice(2, 4);
    let day = raw.slice(4, 6);
    let hour = raw.slice(6, 8);
    let minute = raw.slice(8, 10);
    let second = raw.slice(10, 12);

    return `${year}-${month}-${day} ${hour}:${minute}:${second}`;
}

// 🔹 Loop dengan pembagian data tetap per 3 elemen (1 sensor)
let totalSensors = Math.floor(values.length / 3);

for (let idx = 0; idx < totalSensors; idx++) {
    let base = idx * 3;
    let w1 = values[base];
    let w2 = values[base + 1];
    let w3 = values[base + 2];

    // Cek apakah data sensor lengkap
    if (w1 === undefined || w2 === undefined || w3 === undefined) {
        node.warn(`Sensor ${idx + 1} SKIP (data tidak lengkap)`);
        continue;
    }

    // Cek apakah semua data nol/null
    if ((w1 === 0 || w1 === null) &&
        (w2 === 0 || w2 === null) &&
        (w3 === 0 || w3 === null)) {
        node.warn(`Sensor ${idx + 1} SKIP (semua nol/null)`);
        continue;
    }

    // Kalau lolos, baru decode dan buat query
    let datetime = decodeBCDDatetime(w1, w2, w3);
    node.warn(`Sensor ${idx + 1} datetime: ${datetime}`);

    let combinedRaw = `${w1}-${w2}-${w3}`;
    let oldRaw = lastValues[idx] || "";

    if (combinedRaw !== oldRaw) {
        node.warn(`Sensor ${idx + 1} UPDATED: ${combinedRaw}`);

        queries.push({
            topic: `INSERT INTO sensor_histories (pattern_id, sensor_id, time, created_at, updated_at)
                    VALUES (NULL, ${idx + 1}, '${datetime}', '${datetime}', '${datetime}')`
        });

        lastValues[idx] = combinedRaw;
    }
}

context.set("lastValues", lastValues);

node.warn("✅ Queries generated: " + queries.length);
return [queries];
